    const addMembership=async(pageName,groupName)=>{await openEntity('pages',pageName);const stack=q('[aria-label="Page Group rule stack"]');all('button',stack).find(({textContent})=>textContent==='Add to Page Group').click();await pause();const search=q('[aria-label="Search Page Groups to add"]',stack);set(search,groupName);await pause();all('button',q('[aria-label="Page Group membership search results"]',stack)).find(({textContent})=>textContent.startsWith(groupName+' ·')).click();await pause();};
    for(const [pageName,groupName] of [['Cart','Checkout'],['Payment','Checkout'],['Shipping','Delivery'],['Thank you','Confirmation'],['Returns','Support'],['Customer details','Checkout'],['ID verification','Checkout'],['Summary','Checkout'],['Confirmation page','Checkout'],['Product detail Page','Checkout']])await addMembership(pageName,groupName);
    await add('flows','Checkout journey');
    await openFlow('Checkout journey');

    const evidence={},workspace=q('#workspace-pane'),inspector=q('#project-inspector'),initialCanvas=canvas(),initialOutline=outline(),initialBytes=bytes();
    const catalogsInstalled=['Page Groups','Pages','Events'].every((name)=>workspace.contains(catalog(name)));
    const outlineOwned=workspace.contains(initialOutline);
    const inspectorFormFree=!q('#flow-inspector-context').querySelector('form')&&!document.querySelector('#add-flow-step-form');
